import 'package:flutter/material.dart';

class AppCopy {
  AppCopy._(this._code);

  final String _code;

  static AppCopy of(BuildContext context) =>
      AppCopy._(Localizations.localeOf(context).languageCode);

  bool get isEnglish => _code == 'en';

  String t(String key) => (_map[_code] ?? _map['ar']!) [key] ?? key;

  String requiredField(String field) =>
      isEnglish ? 'Please enter $field' : 'يرجى إدخال $field';

  String customerBalanceLine(String phone, String amount) => phone.isEmpty
      ? (isEnglish ? 'Outstanding balance $amount' : 'الرصيد المستحق $amount')
      : (isEnglish
          ? '$phone - Outstanding balance $amount'
          : '$phone - الرصيد المستحق $amount');

